window.__CONTENT__["journal"] = {"items":[{"slug":"chto-takoe-kod-mesta","title":"Что такое КОД МЕСТА","category":"Метод","date":"2026-06-01","author":"Елена Бочарова","summary":"Коротко о том, как читать город, команду и человека как системы — и зачем искать в них точку опоры.","lede":"У каждой системы есть код — и точка опоры внутри неё.","cover":"","tags":["метод","город","система"],"seoTitle":"Что такое метод КОД МЕСТА — Елена Бочарова","seoDescription":"Авторский метод чтения городских, человеческих и управленческих систем и поиска в них точки опоры.","body":"Город, команда, человек, организация — это системы со своей скрытой логикой. КОД МЕСТА — способ читать эту логику и переводить её в решения.\n\nМы начинаем с наблюдения: где система держится, что её опора, а что — лишь декорация. Затем переходим к действию: где встать, на что опереться, с чего начать.\n\nЭтот же метод одинаково работает и в городе, и в бизнесе, и в личной стратегии — меняется лишь масштаб.","published":true},{"slug":"anons-praktikuma-hr","title":"Открыта предзапись на Практикум HR","category":"Анонс","date":"2026-06-15","author":"Елена Бочарова","summary":"Старт ориентировочно 15.09. Онлайн, более 900 часов, государственный диплом о переподготовке.","lede":"Программа для HR-специалистов, которые хотят вырасти до HR BP и HR-директора.","cover":"","tags":["hr","обучение","анонс"],"seoTitle":"Предзапись на Практикум HR — переподготовка","seoDescription":"Практикум для HR с государственным дипломом о переподготовке. Старт 15.09, онлайн, 3 месяца.","body":"Мы открываем предзапись на Практикум HR — программу профессиональной переподготовки для специалистов по работе с персоналом.\n\nФормат — онлайн, записи и живые встречи, более 900 часов за 3 месяца. По итогам — государственный диплом о переподготовке.\n\nОставьте заявку на странице практикума, чтобы попасть в группу первого набора и получить условия предзаписи.","published":true}]};
